// ── Shared Types ────────────────────────────────────────────────────────────

export type TaskStatus = 'todo' | 'in-progress' | 'blocked' | 'review' | 'done' | 'skipped';

export interface TaskResponse {
  id: string;
  shortId: number;
  moduleId: string;
  title: string;
  description: string | null;
  references: string | null;
  status: TaskStatus;
  assignee: string | null;
  subTotal: number;
  subDone: number;
  progressMessage: string | null;
  commitHash: string | null;
  createdAt: string;
  updatedAt: string;
  reportedAt: string | null;
}

import type { Command } from 'commander';
import type { ResolvedConfig } from '../config.js';
import { MtClient } from '../client.js';
import type { TaskResponse } from '../types.js';
import { parseTaskId, resolveTaskId } from '../utils/id.js';
import { outputJson, outputJsonError } from '../utils/json-output.js';

export function registerClaimCommand(
  tasksGroup: Command,
  getConfig: () => ResolvedConfig,
): void {
  tasksGroup
    .command('claim <taskId>')
    .description('领取一个任务')
    .option('--agent <name>', 'Agent 名称（默认使用配置中的 agentName）')
    .option('--json', '以 JSON 格式输出')
    .action(async (taskId: string, opts: { agent?: string; json?: boolean }) => {
      const config = getConfig();
      const client = new MtClient({ baseUrl: config.serverUrl, apiKey: config.apiKey });

      const agentName = opts.agent || config.agentName;
      if (!agentName) {
        if (opts.json) {
          outputJsonError(new Error('未指定 Agent 名称。请使用 --agent <name> 或在配置文件中设置 agentName。'));
        }
        console.error('[错误] 未指定 Agent 名称。请使用 --agent <name> 或在配置文件中设置 agentName。');
        process.exit(1);
      }

      try {
        const parsed = parseTaskId(taskId);
        const fullId = await resolveTaskId(parsed, () =>
          client.get<TaskResponse[]>(`/api/tasks?milestoneId=${encodeURIComponent(config.milestoneId)}`),
        );

        const result = await client.post<TaskResponse>(`/api/tasks/${encodeURIComponent(fullId)}/claim`, {
          assignee: agentName,
        });

        if (opts.json) {
          outputJson(result);
          return;
        }

        console.log(`✓ 已领取 #${result.shortId}「${result.title}」`);
        console.log(`  负责人: ${result.assignee}`);
      } catch (err) {
        if (opts.json) {
          outputJsonError(err);
        }
        if (err instanceof Error) {
          const msg = err.message;
          // Check for 409 conflict
          if (msg.includes('409')) {
            console.error(`✗ 领取失败。任务 ${taskId} 已被其他 Agent 领取。`);
            console.error(`  请执行 'mt-cli tasks list --status todo' 查看可用任务。`);
          } else {
            console.error(msg);
          }
        }
        process.exit(1);
      }
    });
}

#!/usr/bin/env node

import { Command } from 'commander';
import { resolveConfig } from './config.js';
import { registerStatusCommand } from './commands/status.js';
import { registerListCommand } from './commands/list.js';
import { registerClaimCommand } from './commands/claim.js';
import { registerProgressCommand } from './commands/progress.js';
import { registerCompleteCommand } from './commands/complete.js';
import { registerShowCommand } from './commands/show.js';
import { registerMineCommand } from './commands/mine.js';

const __dirname = new URL('.', import.meta.url).pathname;
// Read version from package.json
let version = '0.1.0';
try {
  // eslint-disable-next-line @typescript-eslint/no-require-imports
  const pkg = await import('../package.json', { with: { type: 'json' } });
  version = (pkg.default as Record<string, unknown>)?.version as string ?? version;
} catch {
  // fallback version
}

const program = new Command();

program
  .name('mt-cli')
  .description('Milestone Tracker AI Agent CLI — AI Agent 使用的里程碑跟踪命令行工具')
  .version(version, '-v, --version', '显示版本号')
  .option('--config <path>', '指定配置文件路径');

// Lazy config resolution — only resolve when a command needs it
function getConfig() {
  const opts = program.opts<{ config?: string }>();
  return resolveConfig(opts.config);
}

// Register status command (top-level)
registerStatusCommand(program, getConfig);

// Register tasks subcommand group
const tasks = program
  .command('tasks')
  .description('任务管理命令');

registerListCommand(tasks, getConfig);
registerClaimCommand(tasks, getConfig);
registerProgressCommand(tasks, getConfig);
registerCompleteCommand(tasks, getConfig);
registerShowCommand(tasks, getConfig);
registerMineCommand(tasks, getConfig);

// Parse and execute
program.parse(process.argv);

import type { Command } from 'commander';
import type { ResolvedConfig } from '../config.js';
import { MtClient } from '../client.js';
import type { TaskResponse } from '../types.js';
import { parseTaskId, resolveTaskId } from '../utils/id.js';
import { progressBar } from '../utils/format.js';
import { outputJson, outputJsonError } from '../utils/json-output.js';

export function registerProgressCommand(
  tasksGroup: Command,
  getConfig: () => ResolvedConfig,
): void {
  tasksGroup
    .command('progress <taskId>')
    .description('更新任务进度')
    .option('--sub-total <n>', '子任务总数', parseInt)
    .option('--sub-done <n>', '已完成子任务数', parseInt)
    .option('--message <msg>', '进度说明')
    .option('--json', '以 JSON 格式输出')
    .action(async (taskId: string, opts: { subTotal?: number; subDone?: number; message?: string; json?: boolean }) => {
      const config = getConfig();
      const client = new MtClient({ baseUrl: config.serverUrl, apiKey: config.apiKey });

      try {
        const parsed = parseTaskId(taskId);
        const fullId = await resolveTaskId(parsed, () =>
          client.get<TaskResponse[]>(`/api/tasks?milestoneId=${encodeURIComponent(config.milestoneId)}`),
        );

        const body: Record<string, unknown> = {};
        if (opts.message) body.progressMessage = opts.message;
        if (opts.subTotal !== undefined) body.subTotal = opts.subTotal;
        if (opts.subDone !== undefined) body.subDone = opts.subDone;

        const result = await client.post<TaskResponse>(`/api/tasks/${encodeURIComponent(fullId)}/progress`, body);

        if (opts.json) {
          outputJson(result);
          return;
        }

        console.log(`✓ 已更新 #${result.shortId}「${result.title}」的进度`);
        if (result.subTotal > 0) {
          console.log(`  ${progressBar(result.subDone, result.subTotal)} (${result.subDone}/${result.subTotal})`);
        }
        if (result.progressMessage) {
          console.log(`  说明: ${result.progressMessage}`);
        }
      } catch (err) {
        if (opts.json) {
          outputJsonError(err);
        }
        if (err instanceof Error) {
          console.error(err.message);
        }
        process.exit(1);
      }
    });
}

// ── JSON Output Utilities ───────────────────────────────────────────────────
// Shared formatting for --json flag across all CLI commands.

import { MtCliError } from '../client.js';

// ── Public API ──────────────────────────────────────────────────────────────

export interface JsonErrorShape {
  error: string;
  code: string;
  details?: unknown;
}

/**
 * Write a JSON payload to stdout (pretty-printed, trailing newline).
 */
export function outputJson(data: unknown): void {
  process.stdout.write(JSON.stringify(data, null, 2) + '\n');
}

/**
 * Format an error as structured JSON, write to stdout, and exit with code 1.
 * Never returns (return type is `never`).
 */
export function outputJsonError(err: unknown): never {
  const payload: JsonErrorShape = {
    error: getErrorMessage(err),
    code: formatErrorCode(err),
  };

  const details = formatErrorDetails(err);
  if (details !== undefined) {
    payload.details = details;
  }

  process.stdout.write(JSON.stringify(payload, null, 2) + '\n');
  process.exit(1);
}

// ── Error Code Mapping ──────────────────────────────────────────────────────

/**
 * Map an error to a machine-readable code string.
 *
 * - MtCliError with HTTP status → `HTTP_${status}` (e.g. `HTTP_404`)
 * - MtCliError with status 0 and abort message → `TIMEOUT`
 * - MtCliError with status 0 and fetch message → `NETWORK_ERROR`
 * - Anything else → `UNKNOWN_ERROR`
 */
export function formatErrorCode(err: unknown): string {
  if (err instanceof MtCliError) {
    if (err.status === 0) {
      // Timeout: abort-related message
      if (err.message.includes('请求超时') || err.message.includes('timeout')) {
        return 'TIMEOUT';
      }
      // Network: fetch-related message
      if (err.message.includes('无法连接') || err.message.includes('fetch')) {
        return 'NETWORK_ERROR';
      }
    }
    if (err.status > 0) {
      return `HTTP_${err.status}`;
    }
  }
  return 'UNKNOWN_ERROR';
}

/**
 * Extract structured details from MtCliError (url, suggestion),
 * or return undefined for unknown error types.
 */
export function formatErrorDetails(err: unknown): unknown {
  if (err instanceof MtCliError) {
    const details: Record<string, string> = {};
    if (err.url) details.url = err.url;
    if (err.suggestion) details.suggestion = err.suggestion;
    if (Object.keys(details).length > 0) return details;
  }
  return undefined;
}

// ── Internal Helpers ────────────────────────────────────────────────────────

function getErrorMessage(err: unknown): string {
  if (err instanceof Error) {
    return err.message;
  }
  if (typeof err === 'string') {
    return err;
  }
  return String(err);
}

// ── Task ID Parsing and Resolution ──────────────────────────────────────────

import type { TaskResponse } from '../types.js';

export interface ParsedTaskId {
  type: 'full' | 'short';
  fullId?: string;      // TASK-{seq}
  shortId?: number;     // N (from #N)
}

/**
 * Parse task ID input.
 * - `#N` → short ID reference
 * - `TASK-{seq}` → full ID
 * - Bare number → treated as short ID
 */
export function parseTaskId(input: string): ParsedTaskId {
  const trimmed = input.trim();

  // #N format
  const shortMatch = trimmed.match(/^#(\d+)$/);
  if (shortMatch) {
    return { type: 'short', shortId: parseInt(shortMatch[1], 10) };
  }

  // TASK-{seq} format
  const fullMatch = trimmed.match(/^TASK-(\d+)$/i);
  if (fullMatch) {
    return { type: 'full', fullId: `TASK-${fullMatch[1]}` };
  }

  // Bare number → treat as short ID
  const bareNum = trimmed.match(/^(\d+)$/);
  if (bareNum) {
    return { type: 'short', shortId: parseInt(bareNum[1], 10) };
  }

  // Unknown format — pass through as full ID
  return { type: 'full', fullId: trimmed };
}

/**
 * Resolve a parsed task ID to a full task ID.
 * If it's a short ID, look up the full ID from the task list.
 */
export async function resolveTaskId(
  parsed: ParsedTaskId,
  listTasks: () => Promise<TaskResponse[]>,
): Promise<string> {
  if (parsed.type === 'full' && parsed.fullId) {
    return parsed.fullId;
  }

  if (parsed.type === 'short' && parsed.shortId !== undefined) {
    const tasks = await listTasks();
    const match = tasks.find((t) => t.shortId === parsed.shortId);
    if (!match) {
      throw new Error(
        `[错误] 未找到编号 #${parsed.shortId} 的任务。请使用 'mt-cli tasks list' 查看所有任务。`
      );
    }
    return match.id;
  }

  throw new Error(`[错误] 无法解析任务 ID: ${JSON.stringify(parsed)}`);
}

/**
 * Find a task by short ID from a list.
 */
export function findByShortId(tasks: TaskResponse[], shortId: number): TaskResponse | undefined {
  return tasks.find((t) => t.shortId === shortId);
}

/**
 * Integration-style tests for --json output across all 7 CLI commands.
 *
 * Strategy:
 * - Mock globalThis.fetch to return controlled API responses.
 * - Create a Commander program per test, register the command, and call
 *   the action handler directly (avoids process.exit from Commander).
 * - Spy on process.stdout.write to capture JSON output.
 * - Stub process.exit so outputJsonError doesn't kill the test runner.
 */

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { Command } from 'commander';
import type { ResolvedConfig } from '../config.js';
import type { TaskResponse } from '../types.js';
import { MtCliError } from '../client.js';

// ── Test Fixtures ───────────────────────────────────────────────────────────

const mockTask1: TaskResponse = {
  id: 'TASK-1',
  shortId: 1,
  moduleId: 'MOD-1-1',
  title: '搭建项目基础结构',
  description: '初始化项目依赖',
  references: null,
  status: 'done',
  assignee: 'agent-alpha',
  subTotal: 5,
  subDone: 5,
  progressMessage: '已完成所有子任务',
  commitHash: 'abc1234',
  createdAt: '2025-01-15T10:00:00Z',
  updatedAt: '2025-01-20T15:30:00Z',
  reportedAt: '2025-01-20T15:30:00Z',
};

const mockTask2: TaskResponse = {
  id: 'TASK-2',
  shortId: 2,
  moduleId: 'MOD-1-1',
  title: '实现用户认证模块',
  description: '实现 JWT 认证',
  references: null,
  status: 'in-progress',
  assignee: 'agent-beta',
  subTotal: 3,
  subDone: 1,
  progressMessage: 'JWT 签发已完成',
  commitHash: null,
  createdAt: '2025-01-16T09:00:00Z',
  updatedAt: '2025-01-21T11:00:00Z',
  reportedAt: null,
};

const mockTask3: TaskResponse = {
  id: 'TASK-3',
  shortId: 3,
  moduleId: 'MOD-1-2',
  title: '编写 API 文档',
  description: null,
  references: 'https://example.com/docs',
  status: 'todo',
  assignee: null,
  subTotal: 0,
  subDone: 0,
  progressMessage: null,
  commitHash: null,
  createdAt: '2025-01-17T08:00:00Z',
  updatedAt: '2025-01-17T08:00:00Z',
  reportedAt: null,
};

const allMockTasks: TaskResponse[] = [mockTask1, mockTask2, mockTask3];

const mockConfig: ResolvedConfig = {
  serverUrl: 'http://localhost:5173',
  milestoneId: 'MS-1',
  apiKey: 'test-api-key',
  agentName: 'agent-alpha',
  configPath: '/fake/.mt-cli.json',
};

// ── Helpers ─────────────────────────────────────────────────────────────────

function makeMockFetch(response: {
  ok: boolean;
  status: number;
  body?: unknown;
  nonJsonText?: string;
}) {
  return vi.fn().mockResolvedValue({
    ok: response.ok,
    status: response.status,
    text: () =>
      response.nonJsonText !== undefined
        ? Promise.resolve(response.nonJsonText)
        : Promise.resolve(JSON.stringify(response.body)),
  });
}

/**
 * Run a command's action handler and capture stdout.
 * Returns { stdout: string[], exitCode: number }.
 */
async function runCommand(
  registerFn: (parent: Command, getConfig: () => ResolvedConfig) => void,
  args: string[],
  config: ResolvedConfig = mockConfig,
  registerOnParent = false,
): Promise<{ stdout: string[]; stderr: string[]; exitCode: number }> {
  // Build argv: [node, script, ...commandArgs]
  // For registerOnParent, args already include the command name (e.g. ['status', '--json'])
  // For sub-group commands, args include the group + command (e.g. ['tasks', 'list', '--json'])
  const argv = ['node', 'script.js', ...args];
  const stdoutChunks: string[] = [];
  const stderrChunks: string[] = [];
  let exitCode = 0;

  const stdoutSpy = vi.spyOn(process.stdout, 'write').mockImplementation((chunk: string | Uint8Array) => {
    stdoutChunks.push(typeof chunk === 'string' ? chunk : new TextDecoder().decode(chunk));
    return true;
  });
  const stderrSpy = vi.spyOn(process.stderr, 'write').mockImplementation((chunk: string | Uint8Array) => {
    stderrChunks.push(typeof chunk === 'string' ? chunk : new TextDecoder().decode(chunk));
    return true;
  });
  const exitSpy = vi.spyOn(process, 'exit').mockImplementation((code?: number) => {
    exitCode = code ?? 0;
    throw new Error(`__process_exit__${exitCode}`);
  });

  const program = new Command();
  // Prevent Commander from writing to stdout/stderr on its own
  program.configureOutput({
    writeOut: () => {},
    writeErr: () => {},
  });
  program.exitOverride();

  const parent = registerOnParent ? program : program.command('tasks');
  registerFn(parent, () => config);

  try {
    await program.parseAsync(argv);
  } catch (e) {
    // Expected: process.exit throws or Commander's exitOverride throws
    if (!(e instanceof Error && e.message.startsWith('__process_exit__'))) {
      // Re-throw unexpected errors
      const exitErr = e as Error & { code?: string };
      if (exitErr.code !== 'commander.exitOverride') throw e;
    }
  }

  stdoutSpy.mockRestore();
  stderrSpy.mockRestore();
  exitSpy.mockRestore();

  return { stdout: stdoutChunks, stderr: stderrChunks, exitCode };
}

/** Extract JSON from captured stdout chunks. */
function parseStdoutJson(stdout: string[]): unknown {
  const raw = stdout.join('');
  return JSON.parse(raw);
}

/** Extract the last JSON line from stdout (in case of multiple writes). */
function parseLastJsonLine(stdout: string[]): unknown {
  const raw = stdout.join('');
  // Find JSON content: look for complete JSON objects in the output
  // The output might have ANSI codes or other artifacts
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error(`No JSON found in stdout: ${JSON.stringify(raw.slice(0, 200))}`);
  return JSON.parse(jsonMatch[0]);
}

// ── list --json ─────────────────────────────────────────────────────────────

describe('list --json', () => {
  let originalFetch: typeof globalThis.fetch;

  beforeEach(() => {
    originalFetch = globalThis.fetch;
    vi.spyOn(console, 'log').mockImplementation(() => {});
    vi.spyOn(console, 'error').mockImplementation(() => {});
  });

  afterEach(() => {
    globalThis.fetch = originalFetch;
    vi.restoreAllMocks();
  });

  it('outputs JSON array with all tasks', async () => {
    const { registerListCommand } = await import('../commands/list.js');
    globalThis.fetch = makeMockFetch({ ok: true, status: 200, body: allMockTasks });

    const { stdout, exitCode } = await runCommand(registerListCommand, [
      'tasks', 'list', '--json',
    ], mockConfig);

    expect(exitCode).toBe(0);
    const parsed = parseStdoutJson(stdout);
    expect(Array.isArray(parsed)).toBe(true);
    expect(parsed).toHaveLength(3);
    expect((parsed as TaskResponse[])[0].shortId).toBe(1);
  });

  it('outputs empty array when no tasks', async () => {
    const { registerListCommand } = await import('../commands/list.js');
    globalThis.fetch = makeMockFetch({ ok: true, status: 200, body: [] });

    const { stdout, exitCode } = await runCommand(registerListCommand, [
      'tasks', 'list', '--json',
    ], mockConfig);

    expect(exitCode).toBe(0);
    const parsed = parseStdoutJson(stdout);
    expect(parsed).toEqual([]);
  });

  it('outputs error JSON on HTTP 401', async () => {
    const { registerListCommand } = await import('../commands/list.js');
    globalThis.fetch = makeMockFetch({
      ok: false,
      status: 401,
      body: { error: 'unauthorized', message: 'API 密钥无效' },
    });

    const { stdout, exitCode } = await runCommand(registerListCommand, [
      'tasks', 'list', '--json',
    ], mockConfig);

    expect(exitCode).toBe(1);
    const parsed = parseLastJsonLine(stdout) as { error: string; code: string };
    expect(parsed.code).toBe('HTTP_401');
    expect(parsed.error).toBeTruthy();
  });

  it('outputs error JSON on HTTP 500', async () => {
    const { registerListCommand } = await import('../commands/list.js');
    globalThis.fetch = makeMockFetch({
      ok: false,
      status: 500,
      body: { error: 'internal', message: '服务器内部错误' },
    });

    const { stdout, exitCode } = await runCommand(registerListCommand, [
      'tasks', 'list', '--json',
    ], mockConfig);

    expect(exitCode).toBe(1);
    const parsed = parseLastJsonLine(stdout) as { error: string; code: string };
    expect(parsed.code).toBe('HTTP_500');
  });

  it('includes done/skipped tasks in JSON output (no filtering)', async () => {
    const { registerListCommand } = await import('../commands/list.js');
    globalThis.fetch = makeMockFetch({ ok: true, status: 200, body: allMockTasks });

    const { stdout } = await runCommand(registerListCommand, [
      'tasks', 'list', '--json',
    ], mockConfig);

    const parsed = parseStdoutJson(stdout) as TaskResponse[];
    // mockTask1 is 'done' — should still be present in JSON output
    expect(parsed.find((t) => t.shortId === 1 && t.status === 'done')).toBeTruthy();
  });
});

// ── show --json ─────────────────────────────────────────────────────────────

describe('show --json', () => {
  let originalFetch: typeof globalThis.fetch;

  beforeEach(() => {
    originalFetch = globalThis.fetch;
    vi.spyOn(console, 'log').mockImplementation(() => {});
    vi.spyOn(console, 'error').mockImplementation(() => {});
  });

  afterEach(() => {
    globalThis.fetch = originalFetch;
    vi.restoreAllMocks();
  });

  it('outputs single task JSON with all fields', async () => {
    const { registerShowCommand } = await import('../commands/show.js');
    // First call: resolveTaskId fetches task list; second call: fetches task detail
    globalThis.fetch = vi.fn()
      .mockResolvedValueOnce({
        ok: true, status: 200,
        text: () => Promise.resolve(JSON.stringify(allMockTasks)),
      })
      .mockResolvedValueOnce({
        ok: true, status: 200,
        text: () => Promise.resolve(JSON.stringify(mockTask2)),
      });

    const { stdout, exitCode } = await runCommand(registerShowCommand, [
      'tasks', 'show', '#2', '--json',
    ], mockConfig);

    expect(exitCode).toBe(0);
    const parsed = parseStdoutJson(stdout) as TaskResponse;
    expect(parsed.shortId).toBe(2);
    expect(parsed.title).toBe('实现用户认证模块');
    expect(parsed.assignee).toBe('agent-beta');
  });

  it('outputs error JSON on HTTP 404', async () => {
    const { registerShowCommand } = await import('../commands/show.js');
    // Task list succeeds (for resolveTaskId), detail fetch fails
    globalThis.fetch = vi.fn()
      .mockResolvedValueOnce({
        ok: true, status: 200,
        text: () => Promise.resolve(JSON.stringify(allMockTasks)),
      })
      .mockResolvedValueOnce({
        ok: false, status: 404,
        text: () => Promise.resolve(JSON.stringify({ error: 'not_found', message: 'Task not found' })),
      });

    const { stdout, exitCode } = await runCommand(registerShowCommand, [
      'tasks', 'show', '#2', '--json',
    ], mockConfig);

    expect(exitCode).toBe(1);
    const parsed = parseLastJsonLine(stdout) as { error: string; code: string };
    expect(parsed.code).toBe('HTTP_404');
  });

  it('outputs error JSON for unknown short ID', async () => {
    const { registerShowCommand } = await import('../commands/show.js');
    // Task list returns tasks, but #999 doesn't exist
    globalThis.fetch = makeMockFetch({ ok: true, status: 200, body: allMockTasks });

    const { stdout, exitCode } = await runCommand(registerShowCommand, [
      'tasks', 'show', '#999', '--json',
    ], mockConfig);

    expect(exitCode).toBe(1);
    const parsed = parseLastJsonLine(stdout) as { error: string; code: string };
    expect(parsed.error).toContain('999');
  });

  it('uses full task ID directly without list fetch', async () => {
    const { registerShowCommand } = await import('../commands/show.js');
    // Only one fetch: the task detail (no list fetch for full IDs)
    globalThis.fetch = vi.fn().mockResolvedValueOnce({
      ok: true, status: 200,
      text: () => Promise.resolve(JSON.stringify(mockTask1)),
    });

    const { stdout, exitCode } = await runCommand(registerShowCommand, [
      'tasks', 'show', 'TASK-1', '--json',
    ], mockConfig);

    expect(exitCode).toBe(0);
    const parsed = parseStdoutJson(stdout) as TaskResponse;
    expect(parsed.id).toBe('TASK-1');
    expect(globalThis.fetch).toHaveBeenCalledOnce();
  });
});

// ── mine --json ─────────────────────────────────────────────────────────────

describe('mine --json', () => {
  let originalFetch: typeof globalThis.fetch;

  beforeEach(() => {
    originalFetch = globalThis.fetch;
    vi.spyOn(console, 'log').mockImplementation(() => {});
    vi.spyOn(console, 'error').mockImplementation(() => {});
  });

